import 'dotenv/config';
import express from 'express';
import cors from 'cors';
import morgan from 'morgan';
import { authRouter } from './routes/auth.js';
import { dashboardRouter } from './routes/dashboard.js';
import { crudRouter } from './routes/crud.js';
import { ordersRouter } from './routes/orders.js';
import { ifoodRouter } from './routes/ifood.js';
import { assistantRouter } from './routes/assistant.js';
import { auth } from './middleware/auth.js';
import { startIfoodWorker } from './services/ifood.js';
const app = express();
app.use(cors());
app.use(express.json());
app.use(morgan('dev'));
app.get('/health', (_req, res) => res.json({ status: 'online', app: 'SmartFood PDV API' }));
app.use('/auth', authRouter);
app.use('/dashboard', auth, dashboardRouter);
app.use('/orders', auth, ordersRouter);
app.use('/ifood', auth, ifoodRouter);
app.use('/assistant', auth, assistantRouter);
app.use('/', auth, crudRouter);
app.use((err, _req, res, _next) => {
    console.error(err);
    res.status(500).json({ message: 'Erro interno', details: err.message });
});
const port = Number(process.env.PORT || 3333);
app.listen(port, () => {
    console.log(`SmartFood PDV API rodando na porta ${port}`);
    startIfoodWorker();
});
